// Obtener static data para trackear keywords ya usadas
const staticData = $getWorkflowStaticData('global');
if (!staticData.usedKeywords) {
  staticData.usedKeywords = [];
}

// Extraer keywords del response de DataForSEO
const items = $input.all();
let keywords = [];

for (const item of items) {
  const tasks = item.json.tasks || [];
  for (const task of tasks) {
    const results = task.result || [];
    for (const result of results) {
      const keywordData = result.items || [];
      for (const kw of keywordData) {
        const volume = kw.keyword_info?.search_volume || 0;
        const difficulty = kw.keyword_properties?.keyword_difficulty || 100;
        const keyword = kw.keyword || '';

        if (
          volume > 500 &&
          difficulty < 40 &&
          keyword.length > 3 &&
          !staticData.usedKeywords.includes(keyword)
        ) {
          keywords.push({
            keyword,
            volume,
            difficulty,
            score: volume / (difficulty + 1)
          });
        }
      }
    }
  }
}

// Ordenar por mejor ratio volumen/dificultad
keywords.sort((a, b) => b.score - a.score);

if (keywords.length === 0) {
  // Fallback: keyword base si no hay nuevas
  const fallbacks = [
    'brujo espiritual en Miami',
    'curandero cerca de mi',
    'limpias espirituales Houston',
    'amarres de amor Nueva York',
    'trabajos espirituales Los Angeles'
  ];
  const unused = fallbacks.filter(k => !staticData.usedKeywords.includes(k));
  if (unused.length === 0) {
    throw new Error('No hay keywords disponibles. Reiniciar lista de usadas si es necesario.');
  }
  keywords = [{ keyword: unused[0], volume: 600, difficulty: 20, score: 30 }];
}

const best = keywords[0];
const today = new Date().toISOString().split('T')[0];

// Generar slug limpio
const slug = best.keyword
  .toLowerCase()
  .replace(/[áàäâ]/g, 'a')
  .replace(/[éèëê]/g, 'e')
  .replace(/[íìïî]/g, 'i')
  .replace(/[óòöô]/g, 'o')
  .replace(/[úùüû]/g, 'u')
  .replace(/ñ/g, 'n')
  .replace(/[^a-z0-9\s]/g, '')
  .trim()
  .replace(/\s+/g, '-');

// Marcar como usada
staticData.usedKeywords.push(best.keyword);

return [{
  json: {
    keyword: best.keyword,
    volume: best.volume,
    difficulty: best.difficulty,
    slug: slug,
    date: today,
    filePath: `src/content/blog/${slug}-${today}.md`,
    pageUrl: `https://donjacintonahual.com/blog/${slug}/`
  }
}];

// Extraer el texto del articulo del response de Claude
const claudeResponse = $input.first().json;
const articleContent = claudeResponse.content?.[0]?.text || '';

if (!articleContent || articleContent.length < 500) {
  throw new Error('Claude devolvio contenido vacio o muy corto: ' + articleContent.substring(0, 200));
}

// Datos de la keyword del nodo anterior
const keywordData = $('Seleccionar Mejor Keyword').first().json;

// Codificar el contenido en base64 para GitHub API
const contentBase64 = Buffer.from(articleContent, 'utf-8').toString('base64');

return [{
  json: {
    articleContent,
    contentBase64,
    filePath: keywordData.filePath,
    slug: keywordData.slug,
    date: keywordData.date,
    keyword: keywordData.keyword,
    pageUrl: keywordData.pageUrl,
    wordCount: articleContent.split(/\s+/).length,
    commitMessage: `Blog: ${keywordData.keyword} (${keywordData.date})`
  }
}];
